import React, { useState, useEffect } from 'react';
import './Registration.css';

function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    service: 'Web Development',
    paymentMethod: 'UPI',
    transactionId: '',
    message: ''
  });

  const [price, setPrice] = useState(0);

  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.service]);
  }, [formData.service]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Submitted Data:", formData);
    alert(`Request for ${formData.service} submitted successfully!`);
  };

  return (
    <div className="register-page bg-light py-5">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-7">
            <div className="card shadow-lg border-0 p-4">
              <div className="card-body">
                <h2 className="fw-bold text-center mb-4 text-primary">Service Registration</h2>
                
                <form onSubmit={handleSubmit}>
                  {/* Basic Details */}
                  <div className="mb-3">
                    <label className="form-label fw-bold">Full Name</label>
                    <input type="text" name="name" className="form-control" placeholder="Enter your name" required onChange={handleChange} />
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold">Email Address</label>
                    <input type="email" name="email" className="form-control" placeholder="example@mail.com" required onChange={handleChange} />
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold">Select Service</label>
                    <select name="service" className="form-select shadow-sm" onChange={handleChange} value={formData.service}>
                      <option value="Web Development">Web Development</option>
                      <option value="UI/UX Design">UI/UX Design</option>
                      <option value="App Development">App Development</option>
                      <option value="Assignment Support">Assignment Support</option>
                      <option value="PPT Design">PPT Design</option>
                      <option value="Report Writing">Report Writing</option>
                    </select>
                  </div>

                  {/* Payment Options Section */}
                  <div className="payment-options border rounded p-3 mt-4 bg-white shadow-sm">
                    <div className="d-flex justify-content-between mb-3 border-bottom pb-2">
                      <h6 className="fw-bold m-0">Payment Summary</h6>
                      <span className="badge bg-success fs-6">Total: ₹{price}</span>
                    </div>

                    <label className="form-label small fw-bold">Select Payment Method</label>
                    <div className="d-flex gap-3 mb-3">
                      <div className="form-check border rounded p-2 px-3 flex-fill">
                        <input className="form-check-input" type="radio" name="paymentMethod" id="upi" value="UPI" checked={formData.paymentMethod === 'UPI'} onChange={handleChange} />
                        <label className="form-check-label small" htmlFor="upi">UPI (GPay/PhonePe)</label>
                      </div>
                      <div className="form-check border rounded p-2 px-3 flex-fill">
                        <input className="form-check-input" type="radio" name="paymentMethod" id="bank" value="Bank Transfer" onChange={handleChange} />
                        <label className="form-check-label small" htmlFor="bank">Bank Transfer</label>
                      </div>
                    </div>

                    {/* Conditional Payment Info */}
                    <div className="p-3 bg-light rounded mb-3 border">
                      {formData.paymentMethod === 'UPI' ? (
                        <div>
                          <p className="mb-1 small fw-bold text-muted text-uppercase">Our UPI ID:</p>
                          <p className="mb-0 text-primary fw-bold fs-5">yourname@okaxis</p>
                        </div>
                      ) : (
                        <div className="small">
                          <p className="mb-1 fw-bold text-muted text-uppercase">Bank Account Details:</p>
                          <p className="mb-0">A/C Name: <strong>Your Full Name</strong></p>
                          <p className="mb-0">A/C No: <strong>123456789012</strong></p>
                          <p className="mb-0">IFSC: <strong>SBIN0001234</strong></p>
                        </div>
                      )}
                    </div>

                    <div className="mb-2">
                      <label className="form-label small fw-bold">Transaction Reference ID *</label>
                      <input type="text" name="transactionId" className="form-control form-control-sm" placeholder="e.g. 123456789" required onChange={handleChange} />
                    </div>
                  </div>

                  <button type="submit" className="btn btn-primary w-100 fw-bold py-3 mt-4">
                    CONFIRM & REGISTER
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
